// services/badgeService.ts
import * as Notifications from 'expo-notifications';
import { Platform } from 'react-native';
import useCartStore from '../store/cartStore';

const updateAppBadge = async () => {
  const totalItems = useCartStore.getState().getTotalItems();

  // Android nécessite une permission spécifique pour les badges
  if (Platform.OS === 'android') {
    // La plupart des lanceurs Android supportent setBadgeCountAsync
    await Notifications.setBadgeCountAsync(totalItems);
  } else {
    // iOS supporte nativement setBadgeCountAsync
    await Notifications.setBadgeCountAsync(totalItems);
  }
};

// Appeler cette fonction après chaque modification du panier
// Dans cartStore, ajouter un useEffect ou un subscriber

export default updateAppBadge;
```

