// components/AppBadgeSync.tsx
import { useEffect } from 'react';
import useCartStore from '../store/cartStore';
import updateAppBadge from '../services/badgeService';

const AppBadgeSync = () => {
  const totalItems = useCartStore((state) => state.getTotalItems());

  useEffect(() => {
    // Mettre à jour le badge à chaque changement du totalItems
    updateAppBadge();
  }, [totalItems]);

  // Ce composant ne rend rien, il existe uniquement pour l'effet de bord
  return null;
};

export default AppBadgeSync;

// Dans App.js
<AppBadgeSync />
```

