// services/badgeService.ts
import * as Notifications from 'expo-notifications';
import useCartStore from '../store/cartStore';

let debounceTimer: NodeJS.Timeout | null = null;
const DEBOUNCE_DELAY = 300; // ms

const updateAppBadgeDebounced = () => {
  if (debounceTimer) {
    clearTimeout(debounceTimer);
  }

  debounceTimer = setTimeout(async () => {
    const totalItems = useCartStore.getState().getTotalItems();
    await Notifications.setBadgeCountAsync(totalItems);
    debounceTimer = null;
  }, DEBOUNCE_DELAY);
};

// Dans le store, appeler updateAppBadgeDebounced() au lieu de updateAppBadge()
```

**Explication :** Si l'utilisateur ajoute 5 produits en moins de 300 ms, seule la dernière mise à jour sera envoyée au système. Cela économise les ressources et évite la surcharge du pont JS-natif.
